patch:
--- a/arithmetic.v
+++ b/arithmetic.v
@@ -1,14 +1,14 @@
 module alu_32bit(
   input [31:0] operand_x, operand_y,
   input [3:0] opcode,
   output reg [31:0] result
 );

-  always @(opcode)
+  always @(*)
   begin
     case(opcode)
       4'h0: result = operand_x + operand_y;
       4'h1: result = operand_x - operand_y;
       4'h2: result = operand_x & operand_y;
       4'h3: result = operand_x | operand_y;
       4'h4: result = operand_x ^ operand_y;
       default: result = 32'b0;
     endcase
   end

before_code:
module alu_32bit(
  input [31:0] operand_x, operand_y,
  input [3:0] opcode,
  output reg [31:0] result
);

  always @(opcode)
  begin
    case(opcode)
      4'h0: result = operand_x + operand_y;
      4'h1: result = operand_x - operand_y;
      4'h2: result = operand_x & operand_y;
      4'h3: result = operand_x | operand_y;
      4'h4: result = operand_x ^ operand_y;
      default: result = 32'b0;
    endcase
  end

endmodule

